st.markdown(
    "<p style='text-align:center;color:#64748b;margin-top:-10px;'>"
    "AI-Powered Early Warning System · Real-Time Sensor Fusion · Autonomous Response</p>",
    unsafe_allow_html=True)

# ── STATUS BAR ──
elapsed = int(time.time() - st.session_state.start_time)
hh, mm_, ss_ = elapsed // 3600, (elapsed % 3600) // 60, elapsed % 60
api_col   = "🟢 ONLINE" if st.session_state.api_ok else "🔴 OFFLINE"
conn_col  = "🟢 ESP32" if connected else "🟡 SIMULATED"
stale_txt = " ⚠️ STALE" if stale else ""
trend_ico = {"RISING": "📈", "FALLING": "📉", "STABLE": "➡️"}.get(trend, "➡️")
mode_lbl  = {"alert": "🔴 ALERT", "recovery": "🟢 RECOVERY", "stable": "🔵 STABLE", "idle": "⚪ IDLE"}.get(speak_mode, "⚪ IDLE")
alert_lbl, _ = alert_level_label(overall_risk)

st.markdown(
    f"<div class='status-bar'>"
    f"⏱ UPTIME: <b>{hh:02d}:{mm_:02d}:{ss_:02d}</b> &nbsp;|&nbsp; "
    f"📡 BACKEND: <b>{api_col}</b> &nbsp;|&nbsp; "
    f"🔌 SENSOR: <b>{conn_col}{stale_txt}</b> &nbsp;|&nbsp; "
    f"{trend_ico} TREND: <b>{trend}</b> &nbsp;|&nbsp; "
    f"⚠️ STATUS: <b>{alert_lbl}</b> &nbsp;|&nbsp; "
    f"🤖 AI: <b>{mode_lbl}</b>"
    f"</div>",
    unsafe_allow_html=True)

st.markdown("---")

# ── ROW 1: BOT FACE + MAIN GAUGE ──
col_bot, col_gauge = st.columns([1, 2])
with col_bot:
    st.markdown(render_bot_face(overall_risk, speaking, speak_mode), unsafe_allow_html=True)
with col_gauge:
    st.plotly_chart(make_main_gauge(overall_risk), use_container_width=True,
                    config={"displayModeBar": False})

# ── ALERT BANNER ──
if overall_risk >= 70:
    st.markdown(
        "<div class='alert-critical'>🚨 ALERT 🚨 &nbsp; DANGER: IMMEDIATE ACTION REQUIRED &nbsp; 🚨 ALERT 🚨</div>",
        unsafe_allow_html=True)
elif overall_risk >= 45:
    st.warning("⚠️ **ELEVATED RISK** — Response systems on standby. Monitoring intensified.")
elif overall_risk >= 20:
    st.info("ℹ️ **LOW RISK** — System stable. Passive monitoring in effect.")
else:
    label = "✅ **RECOVERY**" if speak_mode == "recovery" else "✅ **ALL CLEAR**"
    msg   = "Threat mitigated. Infrastructure returning to normal." if speak_mode == "recovery" else "Infrastructure operating within safe parameters."
    st.success(f"{label} — {msg}")

st.markdown("---")

# ── ROW 2: DISASTER-SPECIFIC RISK GAUGES ──
st.subheader("🎯 Disaster-Specific Risk Breakdown")
gc1, gc2, gc3 = st.columns(3)
with gc1:
    st.plotly_chart(make_gauge("🌊 FLOOD RISK", flood_risk, "#0099ff"),
                    use_container_width=True, config={"displayModeBar": False})
    lbl, col = alert_level_label(flood_risk)
    st.markdown(f"<p style='text-align:center;color:{col};font-weight:bold;margin-top:-10px'>{lbl}</p>", unsafe_allow_html=True)
with gc2:
    st.plotly_chart(make_gauge("🌍 EARTHQUAKE RISK", quake_risk, "#ff0066"),
                    use_container_width=True, config={"displayModeBar": False})
    lbl, col = alert_level_label(quake_risk)
    st.markdown(f"<p style='text-align:center;color:{col};font-weight:bold;margin-top:-10px'>{lbl}</p>", unsafe_allow_html=True)
with gc3:
    st.plotly_chart(make_gauge("🌧️ RAIN RISK", rain_risk, "#00ffaa"),
                    use_container_width=True, config={"displayModeBar": False})
    lbl, col = alert_level_label(rain_risk)
