st.subheader("📡 Live Sensor Telemetry")
c1, c2, c3, c4, c5, c6 = st.columns(6)
rain_icon = {"DRY": "☀️", "WET": "🌧️", "MODERATE": "🌦️"}.get(rain, "❓")
c1.metric(f"{rain_icon} Rain",      rain)
c2.metric("🌊 Water Level",         water, delta=f"{water-WATER_THRESHOLD} vs trigger", delta_color="inverse")
