if vibration == "YES":
    st.warning("⚡ **STRUCTURAL VIBRATION DETECTED** — Possible seismic activity. Review structural integrity.")

st.markdown("---")

# ── ROW 4: TIMELINE PREDICTIONS ──
st.subheader("🔮 AI Risk Timeline Predictions")
t1, t2, t3, t4 = st.columns(4)

def timeline_color(v):
    if v >= 70: return "#dc2626"
    if v >= 45: return "#f59e0b"
    if v >= 20: return "#3b82f6"
    return "#10b981"

with t1:
    col = timeline_color(overall_risk)
    st.markdown(f"<div class='timeline-card'><div class='timeline-label'>NOW</div><div class='timeline-value' style='color:{col}'>{overall_risk:.0f}%</div></div>", unsafe_allow_html=True)
with t2:
    col = timeline_color(future_10)
    arrow = "↑" if future_10 > overall_risk + 2 else ("↓" if future_10 < overall_risk - 2 else "→")
    st.markdown(f"<div class='timeline-card'><div class='timeline-label'>IN 10 SEC</div><div class='timeline-value' style='color:{col}'>{future_10:.0f}% {arrow}</div></div>", unsafe_allow_html=True)
with t3:
    col = timeline_color(future_30)
    arrow = "↑" if future_30 > overall_risk + 2 else ("↓" if future_30 < overall_risk - 2 else "→")
    st.markdown(f"<div class='timeline-card'><div class='timeline-label'>IN 30 SEC</div><div class='timeline-value' style='color:{col}'>{future_30:.0f}% {arrow}</div></div>", unsafe_allow_html=True)
with t4:
    col = timeline_color(future_60)
    arrow = "↑" if future_60 > overall_risk + 2 else ("↓" if future_60 < overall_risk - 2 else "→")
    st.markdown(f"<div class='timeline-card'><div class='timeline-label'>IN 60 SEC</div><div class='timeline-value' style='color:{col}'>{future_60:.0f}% {arrow}</div></div>", unsafe_allow_html=True)

# Trend interpretation
if future_60 > overall_risk + 10:
    st.error(f"🔺 **Escalation predicted:** Risk expected to reach {future_60:.0f}% in 60 seconds. Pre-emptive action advised.")
elif future_60 < overall_risk - 10:
    st.success(f"🔹 **De-escalation predicted:** Risk expected to decrease to {future_60:.0f}% in 60 seconds.")
else:
    st.info(f"➡️ **Stable trajectory:** Risk projected to remain near {future_60:.0f}% over next 60 seconds.")

st.markdown("---")

# ── ROW 5: AI REASONING + TREND CHARTS ──
col_ai, col_charts = st.columns([1, 2])

with col_ai:
    st.subheader("🧠 AI Reasoning Engine")
    st.markdown(f"<div class='ai-panel'>{ai_reasoning}</div>", unsafe_allow_html=True)
    st.caption("Real-time analysis · Rule engine + ML fusion")

with col_charts:
    st.subheader("📈 Real-Time Trend Analysis")
    tab1, tab2, tab3 = st.tabs(["💧 Water Level", "⚠️ Overall Risk", "🎯 Disaster Risks"])
    with tab1:
        st.caption(f"Last {len(st.session_state.water_data)} readings")
        st.line_chart(st.session_state.water_data, height=200)
    with tab2:
        st.caption(f"Last {len(st.session_state.risk_data)} readings")
        st.line_chart(st.session_state.risk_data, height=200)
    with tab3:
        if len(st.session_state.flood_data) > 1:
            import pandas as pd
            chart_df = pd.DataFrame({
                "Flood %":      st.session_state.flood_data,
                "Earthquake %": st.session_state.quake_data,
                "Rain %":       st.session_state.rain_data_hist,
            })
            st.line_chart(chart_df, height=200)
        else:
            st.caption("Collecting data...")

st.markdown("---")

# ── ROW 6: PREDICTIVE RISK MODEL ──
st.subheader("📊 Predictive Risk Index")
window        = st.session_state.risk_data[-5:] if st.session_state.risk_data else [0]
avg_risk      = sum(window) / len(window)
risk_prob_pct = int(clamp(avg_risk))
p1, p2 = st.columns([3, 1])
with p1:
    st.progress(risk_prob_pct / 100)
    st.caption(f"5-sample moving average · Trend: {trend}")
with p2:
    st.metric("Risk Probability", f"{risk_prob_pct}%")

if risk_prob_pct >= 70:
    st.error("🔺 Prediction: Sustained DANGER risk trend — imminent escalation likely.")
elif risk_prob_pct >= 45:
    st.warning("🔸 Prediction: Elevated risk trend — preventive measures advised.")
else:
    st.success("🔹 Prediction: System trending stable — no escalation expected.")

st.markdown("---")

# ── ROW 7: RECOMMENDED ACTIONS ──
cached       = st.session_state.action_cache
sec_left     = max(0, int(ACTION_REFRESH_INTERVAL - (now - st.session_state.action_last_updated)))
body_html    = cached["body"].replace("\n", "<br>")
st.subheader(f"🛠️ Recommended Autonomous Actions  ·  ⏳ next update in {sec_left}s")
